import { formatProfileUrl } from '../Users'
import { FirebaseUser, User } from '../Users/types'
import { getFirAuth } from './firebaseConnect'

export type FavType = 'topics' | 'favPlayers' | 'favTeam' | 'favWLLTeam'

export const NO_USER: User = {
  isLoggedIn: false,
  isAnonymous: false,
  uid: null,
  email: null,
  favPlayers: [],
  topics: [],
}

/**
 * Get Firebase user data (does not consider user logged in until WLL DB confirms)
 */
export const getFirebaseUser = async (): Promise<FirebaseUser> => {
  const auth = await getFirAuth()
  const usr = auth?.currentUser
  if (usr && usr.uid) {
    const firUser: FirebaseUser = {
      isLoggedIn: false,
      isAnonymous: usr.isAnonymous,
      uid: usr.isAnonymous ? null : usr.uid,
    }
    if (usr?.displayName) {
      firUser.firstName = usr.displayName.split(' ')[0]
      firUser.lastName = usr.displayName.split(' ')[1]
    }
    if (usr?.email) firUser.email = usr.email
    if (usr?.phoneNumber) firUser.phone = usr.phoneNumber
    if (usr?.photoURL) firUser.profileUrl = usr.photoURL
    return firUser
  }
  return NO_USER
}

/**
 * Get currently logged user data from firebase (legacy - use getFirebaseUser for new auth flow)
 */
export const getCurrentUser = async (): Promise<FirebaseUser> => {
  const auth = await getFirAuth()
  const usr = auth?.currentUser
  if (usr && usr.uid) {
    // logged in user
    let firUser: FirebaseUser = {
      isLoggedIn: usr.isAnonymous ? false : true,
      isAnonymous: usr.isAnonymous,
      uid: usr.uid,
    }
    if (usr?.displayName) {
      firUser['firstName'] = usr.displayName.split(' ')[0]
      firUser['lastName'] = usr.displayName.split(' ')[1]
    }
    if (usr?.email) {
      firUser['email'] = usr.email
    }
    if (usr?.phoneNumber) {
      firUser['phone'] = usr.phoneNumber
    }
    if (usr?.photoURL) {
      firUser['profileUrl'] = usr.photoURL
    }

    return firUser
  }
  // not logged in
  return NO_USER
}

/**
 * Format user from DB for auth state (PLL-style)
 */
export const formatUpdatedUserData = async (userRes: User): Promise<User> => {
  const userId = userRes?.userId || userRes?.uid
  if (userId) {
    return {
      ...userRes,
      isLoggedIn: true,
      uid: userRes.uid || userId,
      profileUrl: userRes?.profileUrl ? formatProfileUrl(userRes.profileUrl) : '',
    }
  }
  return NO_USER
}

/**
 * Get currently logged user data (legacy)
 */
export const setUpdatedUserData = async (
  userRes: Partial<User> & Record<string, unknown>
): Promise<User> => {
  const usr = (await getFirAuth())?.currentUser
  if (usr && usr.uid) {
    // logged in user
    let userObj: User = {
      isLoggedIn: usr.isAnonymous ? false : true,
      isAnonymous: usr.isAnonymous,
      uid: usr.uid,
      firstName: userRes?.firstName,
      lastName: userRes?.lastName,
      email: userRes?.email,
      profileUrl: userRes?.profileUrl ? formatProfileUrl(userRes.profileUrl) : '',
      phone: usr?.phoneNumber ? usr.phoneNumber : userRes?.phone ? userRes.phone : '',
      birthday: userRes?.birthday || '',
      tw: userRes?.tw || '',
      zip: userRes?.zip || '',
      gamification: userRes?.gamification ? userRes.gamification : false,
      favPlayers: userRes?.favPlayers || [],
    }
    if (userRes?.username) {
      userObj['username'] = userRes.username
    }
    if (userRes?.pllNation) {
      userObj['pllNation'] = userRes.pllNation
    }
    return userObj
  }
  // not logged in
  return NO_USER
}
