import React, { lazy, Suspense } from 'react'
import { BrowserRouter } from 'react-router-dom'
import {
  SHOP_API_VERSION,
  SHOP_STOREFRONT_TOKEN_PUBLIC,
  SHOP_STOREFRONT_URL,
} from './Config/Shop/shop.config'
import { ShopifyProvider } from '@shopify/hydrogen-react'
import { useDynamicTheme } from './Hooks/Theme/useDynamicTheme'
import { ThemeProvider } from '@mui/material/styles'

const AppProviders = lazy(
  () => import(/* webpackChunkName: "app-providers" */ './AppProviders')
)

const App: React.FC<React.PropsWithChildren<unknown>> = () => {
  const { theme } = useDynamicTheme()

  return (
    <BrowserRouter>
      <ThemeProvider theme={theme}>
        <ShopifyProvider
          storeDomain={SHOP_STOREFRONT_URL}
          storefrontToken={SHOP_STOREFRONT_TOKEN_PUBLIC}
          storefrontApiVersion={SHOP_API_VERSION}
          countryIsoCode="US"
          languageIsoCode="EN"
        >
          <Suspense fallback={<></>}>
            <AppProviders />
          </Suspense>
        </ShopifyProvider>
      </ThemeProvider>
    </BrowserRouter>
  )
}

export default App
