import { NO_USER } from '../firebase/AuthData'
import { APIRequestParams, makeAPIRequest, QueryParams } from '../utils/request'
import { getFirAuth } from '../firebase/firebaseConnect'
import { User, UserUpdateData } from './types'
import { API_ENDPOINTS, USER_ENDPOINTS } from '../utils/endpoints'
import { getFirUserAndStatus } from '../../Utils/firebaseHelpers'
import { validatePhoneNumber } from '../../Utils/auth/phoneValidation'
import { MasterLinkParams } from '../../Constants'

export const getUser = async (linkParams: MasterLinkParams | null) => {
  const { user } = await getFirUserAndStatus()
  let headerParams: QueryParams = {}
  if (user) {
    const token = await user.getIdToken()
    headerParams.Authorization = `Bearer ${token}`
  }
  let requestObj: APIRequestParams = {
    method: 'GET',
    apiVersion: '4',
    headerParams: headerParams,
  }
  if (linkParams) {
    requestObj.queryParams = {
      ...linkParams,
    }
  }
  const response = await makeAPIRequest(USER_ENDPOINTS.GET_OR_CREATE_USER, requestObj)
  if (response?.error) {
    //Issue with getting user, use firebase one
    console.error(response.error?.message)
    return null
  }
  return response?.data
}

export const createUser = async (data: User, linkParams: MasterLinkParams | null) => {
  const { user } = await getFirUserAndStatus()
  let headerParams: QueryParams = {}
  if (!user) {
    return Promise.resolve(NO_USER)
  }
  const token = await user.getIdToken()
  headerParams.Authorization = `Bearer ${token}`
  if (linkParams) {
    data = { ...data, ...linkParams }
  }
  let body = JSON.stringify(data)
  const response = await makeAPIRequest(USER_ENDPOINTS.GET_OR_CREATE_USER, {
    method: 'POST',
    apiVersion: '4',
    headerParams: headerParams,
    body: body,
  })
  if (response?.error) {
    //Issue with getting user, use firebase one
    console.error(response.error?.message)
    return null
  }
  return response?.data
}

export const updateUser = async (data: UserUpdateData) => {
  const usr = (await getFirAuth())?.currentUser
  if (!usr) return false
  let headerParams: QueryParams = {}
  if (usr) {
    const token = await usr.getIdToken()
    headerParams.Authorization = `Bearer ${token}`
  }
  let body = JSON.stringify(data)
  try {
    const response = await makeAPIRequest(USER_ENDPOINTS.UPDATE_USER, {
      method: 'PUT',
      apiVersion: '2',
      headerParams: headerParams,
      body: body,
    })
    if (response?.error) {
      console.error(response.error?.message || 'Unknown error')
      return false
    }
    return true
  } catch (err: unknown) {
    console.error(err)
    return false
  }
}

export const updateFavoriteTeam = async (team: string) => {
  if (!team) return { success: false, team: null }
  const data: object = {
    favWLLTeam: team,
  }
  const success = await updateUser(data)
  return { success, team: team }
}

type AuthInputType = 'email' | 'phone'

type CheckUserExistsResponse = { code?: string }

/**
 * Validates if user exists by email/phone. Returns validation code.
 * Uses `phone` query param for E.164-formatted input, `email` otherwise.
 * Pass `type` to override format detection when caller knows the input type.
 */
export const checkValidUser = async (
  input: string | null,
  type?: AuthInputType
): Promise<string | null> => {
  try {
    const auth = await getFirAuth()
    const currentUser = auth?.currentUser
    if (!currentUser) return null

    const token = await currentUser.getIdToken()
    const headerParams: QueryParams = {
      Authorization: `Bearer ${token}`,
    }

    const requestParams: APIRequestParams = {
      method: 'GET',
      apiVersion: '4',
      headerParams,
    }
    if (input) {
      const isPhone =
        type === 'phone' || (type !== 'email' && validatePhoneNumber(input))
      requestParams.queryParams = isPhone ? { phone: input } : { email: input }
    }

    const response = await makeAPIRequest<CheckUserExistsResponse>(
      API_ENDPOINTS.CHECK_USER_EXISTS,
      requestParams
    )

    if (response?.error) {
      console.error('[checkValidUser] Error:', response.error.message)
      return null
    }

    const code = response?.data?.code
    return typeof code === 'string' ? code : null
  } catch (err: unknown) {
    const message = err instanceof Error ? err.message : String(err)
    console.error('[checkValidUser] Exception:', message)
    return null
  }
}