import type { User, UserFavorites } from './types'
import type { User as FirebaseAuthUser } from 'firebase/auth'

/**
 * Maps Firebase Auth User to app User type for createUser/API calls.
 * Converts Firebase field names (displayName, phoneNumber, photoURL) to app schema.
 */
export const mapFirebaseUserToAppUser = (firUsr: FirebaseAuthUser): User => {
  const parts = firUsr.displayName?.trim().split(/\s+/) ?? []
  const firstName = parts[0] ?? null
  const lastName = parts.slice(1).join(' ') || null

  return {
    isLoggedIn: !firUsr.isAnonymous,
    isAnonymous: firUsr.isAnonymous,
    uid: firUsr.uid,
    userId: firUsr.uid,
    email: firUsr.email ?? null,
    phone: firUsr.phoneNumber ?? null,
    firstName: firstName || null,
    lastName: lastName || null,
    profileUrl: firUsr.photoURL ?? null,
    authSource: firUsr.providerData?.[0]?.providerId ?? null,
    topics: [],
    favPlayers: [],
  }
}

export const DEFAULT_EXTRA_LOGIN_FIELDS = ['firstName', 'lastName', 'zip']

export const mapFavorites = (
  user: {
    topics?: string[]
    favPlayers?: string[]
    favTeam?: string | null
    favWLLTeam?: string | null
  } | null
): UserFavorites => {
  if (!user) {
    return { topics: [], favPlayers: [], favTeam: null, favWLLTeam: null }
  }
  const favPlayers = (user.favPlayers || []).map((pl) => {
    return pl.trim().toLowerCase().replace(/\s+/g, '-')
  })
  return {
    topics: user.topics || [],
    favPlayers,
    favTeam: user.favTeam || null,
    favWLLTeam: user.favWLLTeam || null,
  }
}

export const formatProfileUrl = (profileUrl: string) => {
  if (!profileUrl) return
  let containsHttp = profileUrl.includes('https://')
  if (containsHttp) return profileUrl
  return `https://${profileUrl}`
}
